BEGIN;

CREATE TABLE IF NOT EXISTS public.pg253_existing_focused_runtime_rule_promotions_backup AS
SELECT now() AS backed_up_at, r.*
FROM public.card_battle_rules r
WHERE false;

INSERT INTO public.pg253_existing_focused_runtime_rule_promotions_backup
SELECT now() AS backed_up_at, r.*
FROM public.card_battle_rules r
WHERE r.normalized_name IN (SELECT normalized_name FROM (VALUES ('heroes remembered'), ('single combat'), ('the warring triad'), ('toralf, god of fury // toralf''s hammer'), ('unstable glyphbridge // sandswirl wanderglyph'), ('vedalken orrery'), ('wand of vertebrae'), ('whispersilk cloak'), ('wild ricochet')) AS v(normalized_name))
AND NOT EXISTS (SELECT 1 FROM public.pg253_existing_focused_runtime_rule_promotions_backup b WHERE b.normalized_name = r.normalized_name AND b.logical_rule_key = r.logical_rule_key);

DO $$
DECLARE v_missing text;
BEGIN
  WITH proposed(normalized_name, card_name, oracle_hash) AS (VALUES ('heroes remembered', 'Heroes Remembered', '0a349cd92e9d1e5f0f4887e6f12c75b7'), ('single combat', 'Single Combat', 'be6bde23599b29cf800eefe5f11416f6'), ('the warring triad', 'The Warring Triad', '4b71a0484cf31247d62e92ca0bf27efd'), ('toralf, god of fury // toralf''s hammer', 'Toralf, God of Fury // Toralf''s Hammer', '900c199972617df82c6ddf796e2cf04f'), ('unstable glyphbridge // sandswirl wanderglyph', 'Unstable Glyphbridge // Sandswirl Wanderglyph', 'e56f55f81b1f72be8c4e3752f1916898'), ('vedalken orrery', 'Vedalken Orrery', '1fa2fc4b26db2e2d0691f8170d03b4db'), ('wand of vertebrae', 'Wand of Vertebrae', '71de2615587654002b225714c5130a68'), ('whispersilk cloak', 'Whispersilk Cloak', '5384a7231f4c91ab45b4007b0ac7f8dc'), ('wild ricochet', 'Wild Ricochet', 'c7d62b1c3e0178970919cd0fc3b6b995'))
  SELECT string_agg(p.card_name, ', ' ORDER BY p.card_name) INTO v_missing
  FROM proposed p
  WHERE NOT EXISTS (SELECT 1 FROM public.cards c WHERE (lower(c.name) = p.normalized_name OR split_part(lower(c.name), ' // ', 1) = p.normalized_name) AND md5(coalesce(c.oracle_text, '')) = p.oracle_hash);
  IF v_missing IS NOT NULL THEN
    RAISE EXCEPTION 'PG253 abort: expected at least one Oracle-hash-matched cards row for every proposed card: %', v_missing;
  END IF;
END $$;

WITH proposed(normalized_name, card_name, oracle_hash, logical_rule_key, effect_json, deck_role_json, source, confidence, review_status, execution_status, notes, shadow_handling) AS (
  VALUES
    ('heroes remembered', 'Heroes Remembered', '0a349cd92e9d1e5f0f4887e6f12c75b7', 'battle_rule_v1:4978416393dc912bc2d6d090afde8dc8', '{"ability_kind":"one_shot","battle_model_scope":"controller_gain_20_life_suspend_10_w_v1","cmc":9.0,"effect":"life_total_change","life_gain_amount":20,"sorcery":true,"suspend":true,"suspend_cost":"{W}","suspend_time_counters":10}'::jsonb, '{"category":"unknown","effect":"life_total_change"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Heroes Remembered; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('single combat', 'Single Combat', 'be6bde23599b29cf800eefe5f11416f6', 'battle_rule_v1:45c2a4f6d6d4930fb4cb54b8fa886bc2', '{"ability_kind":"one_shot_and_rule_modifier","battle_model_scope":"each_player_keep_one_creature_or_planeswalker_sacrifice_rest_then_creature_planeswalker_cast_lock_v1","cmc":5.0,"colors":["W"],"each_player_chooses_one_creature_or_planeswalker_sacrifices_rest":true,"effect":"single_combat","mana_cost":"{3}{W}{W}","sorcery":true,"spell_type_cast_lock_applies_to":"all_players","spell_type_cast_lock_card_types":["creature","planeswalker"],"spell_type_cast_lock_duration":"until_end_of_your_next_turn"}'::jsonb, '{"category":"unknown","effect":"single_combat"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Single Combat; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('the warring triad', 'The Warring Triad', '4b71a0484cf31247d62e92ca0bf27efd', 'battle_rule_v1:1b92340f98d8dd60da33dbd03e915d23', '{"ability_kind":"static_and_mana_activated","activation_requires_tap":true,"artifact":true,"base_power":5,"base_toughness":5,"battle_model_scope":"legendary_artifact_creature_graveyard_threshold_self_mill_any_color_mana_v1","cmc":3.0,"creature_if_graveyard_count_at_least":8,"creature_type_suppressed_when_graveyard_count_below":8,"effect":"ramp_permanent","flying":true,"haste":true,"is_mana_source":true,"legendary":true,"mana_ability_target":"target_player_self_model","mana_activation_mill_count":1,"mana_activation_requires_tap":true,"mana_cost":"{3}","mana_produced":1,"power":5,"produces":"WUBRG","subtypes":["God"],"toughness":5,"trample":true,"type_line":"Legendary Artifact Creature - God"}'::jsonb, '{"category":"ramp","effect":"ramp_permanent"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for The Warring Triad; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('toralf, god of fury // toralf''s hammer', 'Toralf, God of Fury // Toralf''s Hammer', '900c199972617df82c6ddf796e2cf04f', 'battle_rule_v1:733e913423b3c4471520195c8a814097', '{"ability_kind":"modal_dfc_triggered_static_and_equipment_metadata","back_face_mana_cost":"{1}{R}","back_face_name":"Toralf''s Hammer","back_face_type_line":"Legendary Artifact - Equipment","battle_model_scope":"opponent_creature_excess_noncombat_damage_reflect_any_target_equipment_metadata_v1","cmc":4.0,"colors":["R"],"damage_amount_source":"excess_noncombat_damage","effect":"creature","equip_cost":"{1}{R}","equipped_creature_gains_unattach_damage_any_target":true,"equipped_legendary_creature_power_bonus":3,"excess_noncombat_damage_to_opponent_permanent_reflect_any_target":true,"hammer_activation_cost":"{1}{R}, tap, unattach","hammer_activation_damage":3,"hammer_activation_returns_to_owner_hand":true,"legendary":true,"mana_cost":"{2}{R}{R}","power":5,"subtypes":["God"],"target":"any_target_other_than_damaged_permanent","target_constraints":{"exclude_damaged_permanent":true,"scope":"any_target"},"toughness":4,"trample":true,"trigger":"opponent_permanent_excess_noncombat_damage","trigger_effect":"damage_any_target","type_line":"Legendary Creature - God"}'::jsonb, '{"category":"unknown","effect":"creature","target":"any_target_other_than_damaged_permanent"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Toralf, God of Fury // Toralf''s Hammer; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('unstable glyphbridge // sandswirl wanderglyph', 'Unstable Glyphbridge // Sandswirl Wanderglyph', 'e56f55f81b1f72be8c4e3752f1916898', 'battle_rule_v1:f4168e92445f0a9b9b2de0ef32f4b78d', '{"ability_kind":"etb_selective_creature_wipe_and_transform_metadata","back_face_attacked_you_spell_lock_metadata":true,"back_face_flying":true,"back_face_name":"Sandswirl Wanderglyph","back_face_opponent_spell_cast_attack_lock_metadata":true,"back_face_power":5,"back_face_toughness":3,"back_face_type_line":"Artifact Creature - Golem","battle_model_scope":"etb_choose_small_creature_each_player_destroy_rest_craft_metadata_v1","choose_one_small_creature_each_player_power_max":2,"cmc":5.0,"colors":["W"],"craft_with_artifact":"{3}{W}{W}","destroy_all_other_creatures":true,"effect":"glyphbridge_selective_creature_wipe","etb_if_cast":true,"mana_cost":"{3}{W}{W}","type_line":"Artifact"}'::jsonb, '{"category":"unknown","effect":"glyphbridge_selective_creature_wipe"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Unstable Glyphbridge // Sandswirl Wanderglyph; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('vedalken orrery', 'Vedalken Orrery', '1fa2fc4b26db2e2d0691f8170d03b4db', 'battle_rule_v1:9e2c7c96d5b2a117731924d511bb0e2a', '{"ability_kind":"static","artifact":true,"battle_model_scope":"nonland_spells_as_though_flash_static_v1","cast_nonland_spells_as_flash":true,"cmc":4.0,"effect":"flash_permission","flash_permission_filter":"nonland_spells","mana_cost":"{4}"}'::jsonb, '{"category":"unknown","effect":"flash_permission"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Vedalken Orrery; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('wand of vertebrae', 'Wand of Vertebrae', '71de2615587654002b225714c5130a68', 'battle_rule_v1:ab583f78c19a22031bb99e0ac2d0d131', '{"ability_kind":"activated","activated_self_mill_count":1,"artifact":true,"battle_model_scope":"tap_self_mill_or_self_exile_graveyard_shuffle_artifact_v1","cmc":1.0,"effect":"passive","graveyard_shuffle_activation_cost_generic":2,"graveyard_shuffle_activation_requires_tap":true,"graveyard_shuffle_destination":"library","graveyard_shuffle_exiles_self":true,"graveyard_shuffle_low_library_threshold":8,"graveyard_shuffle_min_targets":3,"graveyard_shuffle_target_controller":"self","graveyard_shuffle_target_count":5,"mana_cost":"{1}","self_mill_activation_requires_tap":true,"self_mill_min_library_after":3}'::jsonb, '{"category":"unknown","effect":"passive"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Wand of Vertebrae; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('whispersilk cloak', 'Whispersilk Cloak', '5384a7231f4c91ab45b4007b0ac7f8dc', 'battle_rule_v1:776e69f786c18a8398012554b8e22907', '{"ability_kind":"static_equipment","artifact":true,"attached_creature_cant_be_blocked":true,"battle_model_scope":"equipment_auto_attach_unblockable_shroud_v1","cmc":3.0,"effect":"equipment_static_attachment","equip_cost":"{2}","equipment":true,"grants_shroud":true,"grants_unblockable":true,"mana_cost":"{3}"}'::jsonb, '{"category":"protection","effect":"equipment_static_attachment"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Whispersilk Cloak; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows'),
    ('wild ricochet', 'Wild Ricochet', 'c7d62b1c3e0178970919cd0fc3b6b995', 'battle_rule_v1:bb9ee6595d8b30aa87f1a15879e2703a', '{"ability_kind":"one_shot","battle_model_scope":"copy_target_instant_or_sorcery_stack_spell_change_original_and_copy_targets_annotation_v1","choose_new_targets_for_target_spell_status":"annotation_only","choose_new_targets_status":"annotation_only","cmc":4.0,"colors":["R"],"copy_is_not_cast":true,"copy_target_stack_object":true,"effect":"copy_spell","instant":true,"mana_cost":"{2}{R}{R}","may_choose_new_targets":true,"may_choose_new_targets_for_target_spell":true,"target":"instant_or_sorcery_on_stack","target_spell_card_types":["instant","sorcery"]}'::jsonb, '{"category":"engine","effect":"copy_spell","target":"instant_or_sorcery_on_stack","timing":"instant"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'PG253: promoted tested exact runtime rule for Wild Ricochet; source is existing ManaLoom focused runtime test plus local XMage/manual rule mapping.', 'deprecate_nonmatching_rows')
), deprecated AS (
  UPDATE public.card_battle_rules r
  SET review_status = 'deprecated', execution_status = 'disabled', updated_at = now(),
      notes = concat_ws(E'\n', nullif(r.notes, ''), 'PG253: disabled stale shadow before curated tested exact runtime promotion.')
  FROM proposed p
  WHERE r.normalized_name = p.normalized_name
    AND p.shadow_handling = 'deprecate_nonmatching_rows'
    AND r.logical_rule_key <> p.logical_rule_key
    AND (r.review_status <> 'deprecated' OR r.execution_status <> 'disabled')
  RETURNING r.*
), target_cards AS (
  SELECT DISTINCT ON (p.normalized_name) p.normalized_name, c.id, c.name
  FROM proposed p
  JOIN public.cards c ON (lower(c.name) = p.normalized_name OR split_part(lower(c.name), ' // ', 1) = p.normalized_name) AND md5(coalesce(c.oracle_text, '')) = p.oracle_hash
  ORDER BY p.normalized_name, c.name
), upserted AS (
  INSERT INTO public.card_battle_rules (normalized_name, logical_rule_key, card_id, card_name, effect_json, deck_role_json, source, confidence, review_status, execution_status, rule_version, oracle_hash, notes, reviewed_by, reviewed_at, created_at, updated_at, last_seen_at)
  SELECT p.normalized_name, p.logical_rule_key, tc.id, tc.name, p.effect_json, p.deck_role_json, p.source, p.confidence, p.review_status, p.execution_status, 1, p.oracle_hash, p.notes, 'codex-pg253', now(), now(), now(), now()
  FROM proposed p
  JOIN target_cards tc ON tc.normalized_name = p.normalized_name
  ON CONFLICT (normalized_name, logical_rule_key) DO UPDATE
  SET card_id=EXCLUDED.card_id, card_name=EXCLUDED.card_name, effect_json=EXCLUDED.effect_json, deck_role_json=EXCLUDED.deck_role_json, source=EXCLUDED.source, confidence=EXCLUDED.confidence, review_status=EXCLUDED.review_status, execution_status=EXCLUDED.execution_status, rule_version=EXCLUDED.rule_version, oracle_hash=EXCLUDED.oracle_hash, notes=EXCLUDED.notes, reviewed_by=EXCLUDED.reviewed_by, reviewed_at=EXCLUDED.reviewed_at, updated_at=now(), last_seen_at=now()
  RETURNING *
)
SELECT (SELECT count(*) FROM deprecated) AS deprecated_rows, (SELECT count(*) FROM upserted) AS upserted_rows;

COMMIT;
